// ============================================================
// CONFIGURACIÓN DE ENTORNO
// Cambiar 'PRODUCCION' por 'TEST' según corresponda
// PRODUCCION → archivos .PFA | TEST → archivos .TFA
// ============================================================
const ENTORNO = 'PRODUCCION';

const extension = ENTORNO === 'PRODUCCION' ? '.PFA' : '.TFA';
const archivos = $input.all();

// Filtrar sólo archivos con la extensión del entorno seleccionado
const archivosXML = archivos
  .filter(f => f.json.name && f.json.name.toUpperCase().endsWith(extension.toUpperCase()))
  .sort((a, b) => new Date(b.json.modifyTime || 0) - new Date(a.json.modifyTime || 0));

if (archivosXML.length === 0) {
  throw new Error(`No se encontraron archivos ${extension} en BackUpSeparador.`);
}

// Seleccionar el archivo más reciente
const archivo = archivosXML[0].json;

return [{
  json: {
    fileName: archivo.name,
    filePath: `/Directorios/FTP/1028501021/BackUpSeparador/${archivo.name}`,
    entorno: ENTORNO,
    extension: extension,
    totalArchivosEncontrados: archivosXML.length,
    fechaProceso: new Date().toISOString().split('T')[0]
  }
}];

// Extrae todos los códigos SAP del campo <TextoLibre1> del XML descargado
const item = $input.first();
const fileInfo = $('Seleccionar Archivo XML').first().json;

// El FTP download devuelve el archivo como binario
const binaryData = item.binary?.data;
if (!binaryData) {
  throw new Error('No se recibió contenido binario del archivo XML desde el FTP.');
}
const xmlContent = Buffer.from(binaryData.data, 'base64').toString('utf-8');

// Extraer todos los valores dentro de <TextoLibre1>...</TextoLibre1>
const regex = /<TextoLibre1>([^<]+)<\/TextoLibre1>/g;
const codigosSAP = [];
let match;

while ((match = regex.exec(xmlContent)) !== null) {
  const codigo = match[1].trim();
  if (codigo && !codigosSAP.includes(codigo)) {
    codigosSAP.push(codigo);
  }
}

if (codigosSAP.length === 0) {
  throw new Error(`No se encontraron códigos SAP (TextoLibre1) en: ${fileInfo.fileName}`);
}

// Formatea para usar directamente en cláusula SQL IN (ej: '2600464615', '2600464220')
const codesForSQL = codigosSAP.map(c => `'${c}'`).join(', ');

return [{
  json: {
    codigosSAP,
    totalDocumentosXML: codigosSAP.length,
    codesForSQL,
    fileName: fileInfo.fileName,
    entorno: fileInfo.entorno,
    fechaProceso: fileInfo.fechaProceso,
    xmlOriginal: xmlContent
  }
}];

// Cruza los códigos SAP del XML contra los registros encontrados en BD
const datosXML = $('Extraer Códigos SAP').first().json;
const registrosBD = $input.all();

const codigosSAP = datosXML.codigosSAP;

// Separar por estado
const procesados = registrosBD.filter(r => r.json.resultado && r.json.resultado !== 'R');
const rechazados = registrosBD.filter(r => r.json.resultado === 'R');

// Todos los códigos que sí aparecen en BD (cualquier estado)
const codigosEnBD = registrosBD.map(r => String(r.json.codigoerp));

// Códigos del XML que NO están en BD (faltantes totales)
const codigosFaltantes = codigosSAP.filter(c => !codigosEnBD.includes(String(c)));

// Determinar estado global
const hayFaltantes   = codigosFaltantes.length > 0;
const hayRechazados  = rechazados.length > 0;
const todosCoinciden = !hayFaltantes && !hayRechazados;

let estadoProceso;
if (todosCoinciden)              estadoProceso = 'EXITOSO';
else if (hayFaltantes && hayRechazados) estadoProceso = 'FALTANTES_Y_RECHAZADOS';
else if (hayFaltantes)           estadoProceso = 'DOCUMENTOS_FALTANTES';
else                             estadoProceso = 'DOCUMENTOS_RECHAZADOS';

const detalleRechazados = rechazados.map(r => ({
  codigoERP: r.json.codigoerp,
  fecha:     r.json.fechacbte,
  resultado: r.json.resultado,
  error:     r.json.errordesc
}));

return [{
  json: {
    estadoProceso,
    todosCoinciden,
    // Conteos
    totalDocumentosXML:  datosXML.totalDocumentosXML,
    cantidadProcesados:  procesados.length,
    cantidadRechazados:  rechazados.length,
    cantidadFaltantes:   codigosFaltantes.length,
    totalEnBD:           procesados.length + rechazados.length,
    // Detalle
    codigosFaltantes,
    detalleRechazados,
    // Metadata
    fileName:            datosXML.fileName,
    entorno:             datosXML.entorno,
    fechaProceso:        datosXML.fechaProceso,
    timestampAnalisis:   new Date().toISOString()
  }
}];
